#include <bits/stdc++.h>
using namespace std;
int main(){int t;cin>>t;while(t--){int n,m;cin>>n>>m;deque<pair<int,int>>q;multiset<int>pr;for(int i=0;i<n;i++){int p;cin>>p;q.push_back({p,i});pr.insert(p);}int cnt=0;while(true){auto f=q.front();q.pop_front();if(!pr.empty()&&*pr.rbegin()>f.first){q.push_back(f);}else{pr.erase(pr.find(f.first));cnt++;if(f.second==m){cout<<cnt<<"\n";break;}}}}}
